{
  "mode": "method",
  "tests": [
    {
      "name": "valid_login",
      "input": {
        "username": "validUser",
        "password": "validPassword"
      },
      "output": {
        "status": "success",
        "message": "Login successful",
        "roles": ["user", "admin"]
      },
      "notes": "Tests a valid login scenario."
    },
    {
      "name": "invalid_login",
      "input": {
        "username": "invalidUser",
        "password": "invalidPassword"
      },
      "output": {
        "status": "error",
        "message": "Invalid credentials"
      },
      "notes": "Tests an invalid login scenario."
    },
    {
      "name": "missing_username",
      "input": {
        "username": "",
        "password": "somePassword"
      },
      "output": {
        "status": "error",
        "message": "Username is required"
      },
      "notes": "Tests edge case of missing username."
    },
    {
      "name": "missing_password",
      "input": {
        "username": "someUser",
        "password": ""
      },
      "output": {
        "status": "error",
        "message": "Password is required"
      },
      "notes": "Tests edge case of missing password."
    },
    {
      "name": "role_lookup_valid",
      "input": {
        "userId": 1
      },
      "output": {
        "status": "success",
        "roles": ["user", "admin"]
      },
      "notes": "Tests role lookup for a valid user."
    },
    {
      "name": "role_lookup_invalid_user",
      "input": {
        "userId": 9999
      },
      "output": {
        "status": "error",
        "message": "User not found"
      },
      "notes": "Tests role lookup for a non-existent user."
    },
    {
      "name": "login_with_special_characters",
      "input": {
        "username": "user!@#",
        "password": "pass$%^"
      },
      "output": {
        "status": "success",
        "message": "Login successful",
        "roles": ["user"]
      },
      "notes": "Tests login with special characters in username and password."
    },
    {
      "name": "login_rate_limiting",
      "input": {
        "username": "rateLimitedUser",
        "password": "password"
      },
      "output": {
        "status": "error",
        "message": "Too many login attempts"
      },
      "notes": "Tests the system's response to too many login attempts."
    }
  ],
  "assumptions": "The database is properly seeded with test users and roles.",
  "notes": "Ensure that the tests cover both successful and error scenarios."
}
